                    ntotal_fired_weights += float(self.fired_masks[name_cur].sum().item())
                    ntotal_weights += float(self.fired_masks[name_cur].numel())
                    layer_fired_weights[name_cur] = float(self.fired_masks[name_cur].sum().item())/float(self.fired_masks[name_cur].numel())
                    print('Layerwise percentage of the fired weights of', name, 'is:', layer_fired_weights[name_cur])
            total_fired_weights = ntotal_fired_weights/ntotal_weights
            print('The percentage of the total fired weights is:', total_fired_weights)
            return layer_fired_weights, total_fired_weights

    def synchronism_masks(self, pruning_type='unstructure'):
        if pruning_type == "unstructure":
            for name in self.masks.keys():
                torch.distributed.broadcast(self.masks[name], src=0, async_op=False)
        elif pruning_type == 'structure':
            for name in self.other_masks.keys():
                torch.distributed.broadcast(self.other_masks[name], src=0, async_op=False)
            for name in self.atten_masks.keys():
                torch.distributed.broadcast(self.atten_masks[name], src=0, async_op=False)
        elif pruning_type == 'structure_new':
            for name in self.other_masks.keys():
                torch.distributed.broadcast(self.other_masks[name], src=0, async_op=False)
            for name in self.atten_masks.keys():
                torch.distributed.broadcast(self.atten_masks[name], src=0, async_op=False)
        else:
            raise ValueError('Unrecognized Pruning Type !')

    # NOTE: optimizer momentum accessor needed by growth modes (defined on optimizers that support it)
    def get_momentum_for_weight(self, weight):
        state = self.optimizer.state.get(weight, None)
        if state is not None and 'momentum_buffer' in state:
            return state['momentum_buffer']
        return torch.zeros_like(weight)


# --------- vision_transformer.py (Attention head importance with first-order Taylor) ---------
import torch
import torch.nn as nn
from timm.models.layers import DropPath, to_2tuple, trunc_normal_
import torch.nn.functional as F

class Attention(nn.Module):
    def __init__(self, dim, num_heads=8, qkv_bias=False, qk_scale=None, attn_drop=0., proj_drop=0.):
        super().__init__()
        self.num_heads = num_heads
        head_dim = dim // num_heads
        self.scale = qk_scale or head_dim ** -0.5
        self.qkv = nn.Linear(dim, dim * 3, bias=qkv_bias)
        self.attn_drop = nn.Dropout(attn_drop)
        self.proj = nn.Linear(dim, dim)
        self.proj_drop = nn.Dropout(proj_drop)
        self.atten_values = None
        self.grad_scores = None
        self.grad_norm = None

    def _score(self, grad):
        # grad, atten_values shape: (B, N, num_heads, head_dim)
        # First-order Taylor score: |A^T · dL/dA| per head (averaged over batch)
        self.grad_scores = torch.einsum('bnhl,bnhl->bh', grad, self.atten_values).abs().mean(dim=0)
        # Gradient L1 per head (averaged) for growth criterion when disabled
        self.grad_norm = grad.norm(dim=(1,3), p=1).mean(dim=0)

    def forward(self, x):
        B, N, C = x.shape
        qkv = self.qkv(x).reshape(B, N, 3, self.num_heads, C // self.num_heads).permute(2, 0, 3, 1, 4)
        q, k, v = qkv[0], qkv[1], qkv[2]
        attn = (q @ k.transpose(-2, -1)) * self.scale
        attn = attn.softmax(dim=-1)
        attn = self.attn_drop(attn)
        x = (attn @ v).transpose(1, 2)
        if self.training:
            self.atten_values = x
            x.register_hook(self._score)
        x = x.reshape(B, N, C)
        x = self.proj(x)
        x = self.proj_drop(x)
        return x

# Excerpt: Block that uses Attention above to optionally emit indicators (used in legacy structure path)
class Block(nn.Module):
    def __init__(self, dim, num_heads, mlp_ratio=4., qkv_bias=False, qk_scale=None, drop=0., attn_drop=0.,
                 drop_path=0., act_layer=nn.GELU, norm_layer=nn.LayerNorm):
        super().__init__()
        self.norm1 = norm_layer(dim)
        self.attn = Attention(dim, num_heads=num_heads, qkv_bias=qkv_bias, qk_scale=qk_scale, attn_drop=attn_drop, proj_drop=drop)
        self.drop_path = DropPath(drop_path) if drop_path > 0. else nn.Identity()
        self.norm2 = norm_layer(dim)
        mlp_hidden_dim = int(dim * mlp_ratio)
        self.mlp = nn.Sequential(nn.Linear(dim, mlp_hidden_dim), act_layer(), nn.Dropout(drop), nn.Linear(mlp_hidden_dim, dim), nn.Dropout(drop))

    def forward(self, x):
        x = x + self.drop_path(self.attn(self.norm1(x)))
        x = x + self.drop_path(self.mlp(self.norm2(x)))
        return x


# --------- vision_transformer_data.py (SViTE+: token selector via Gumbel-Softmax with STE) ---------
import torch
import torch.nn as nn
from timm.models.layers import DropPath, to_2tuple, trunc_normal_
import torch.nn.functional as F

# Gumbel-Softmax and scatter helpers

def scatter(logits, index, k):
    bs = logits.shape[0]
    x_index = torch.arange(bs).reshape(-1, 1).expand(bs,k)
    x_index = x_index.reshape(-1).tolist()
    y_index = index.reshape(-1).tolist()
    output = torch.zeros_like(logits).cuda()
    output[x_index, y_index] = 1.0
    return output

def gumbel_softmax(logits, k, tau=1, hard=False, eps=1e-10, dim=-1):
    def _gen_gumbels():
        gumbels = -torch.empty_like(logits).cuda().exponential_().log()
        if torch.isnan(gumbels).sum() or torch.isinf(gumbels).sum():
            gumbels = _gen_gumbels()
        return gumbels
    gumbels = _gen_gumbels()
    gumbels = (logits + gumbels) / tau
    y_soft = gumbels.softmax(dim)
    if hard:
        index = y_soft.topk(k, dim=dim)[1]
        y_hard = scatter(logits, index, k)
        ret = y_hard - y_soft.detach() + y_soft
    else:
        ret = y_soft
    if torch.isnan(ret).sum():
        raise OverflowError('gumbel softmax output NaN/Inf')
    return ret

class Attention_Token(nn.Module):
    def __init__(self, dim, num_heads=8, qkv_bias=False, qk_scale=None, attn_drop=0., proj_drop=0.):
        super().__init__()
        self.num_heads = num_heads
        head_dim = dim // num_heads
        self.scale = qk_scale or head_dim ** -0.5
        self.qkv = nn.Linear(dim, dim * 3, bias=qkv_bias)
        self.gumbel = nn.Linear(dim,1)  # learnable token scorer (MLP reduced to 1-layer)
        self.attn_drop = nn.Dropout(attn_drop)
        self.proj = nn.Linear(dim, dim)
        self.proj_drop = nn.Dropout(proj_drop)
        self.score = False
        self.atten_values = None
        self.grad_scores = None
        self.grad_norm = None

    def forward(self, x, tau=-1, number=197):
        B, N, C = x.shape
        if tau > 0:
            token_scores = self.gumbel(x).reshape(B, -1)
            token_mask = gumbel_softmax(F.log_softmax(token_scores, dim=-1), k=number, tau=tau, hard=True)
            token_mask[:,0] = 1.0  # always keep [CLS]
            token_mask = token_mask.expand(C,-1,-1).permute(1,2,0)
            x = x * token_mask
        qkv = self.qkv(x).reshape(B, N, 3, self.num_heads, C // self.num_heads).permute(2, 0, 3, 1, 4)
        q, k, v = qkv[0], qkv[1], qkv[2]
        attn = (q @ k.transpose(-2, -1)) * self.scale
        attn = attn.softmax(dim=-1)
        attn = self.attn_drop(attn)
        x = (attn @ v).transpose(1, 2).reshape(B, N, C)
        x = self.proj(x)
        x = self.proj_drop(x)
        return x

class Block_Token(nn.Module):
    def __init__(self, dim, num_heads, mlp_ratio=4., qkv_bias=False, qk_scale=None, drop=0., attn_drop=0.,
                 drop_path=0., act_layer=nn.GELU, norm_layer=nn.LayerNorm):
        super().__init__()
        self.norm1 = norm_layer(dim)
        self.attn = Attention_Token(dim, num_heads=num_heads, qkv_bias=qkv_bias, qk_scale=qk_scale, attn_drop=attn_drop, proj_drop=drop)
        self.drop_path = DropPath(drop_path) if drop_path > 0. else nn.Identity()
        self.norm2 = norm_layer(dim)
        mlp_hidden_dim = int(dim * mlp_ratio)
        self.mlp = nn.Sequential(nn.Linear(dim, mlp_hidden_dim), act_layer(), nn.Dropout(drop), nn.Linear(mlp_hidden_dim, dim), nn.Dropout(drop))

    def forward(self, x, tau, number):
        x = x + self.drop_path(self.attn(self.norm1(x), tau=tau, number=number))
        x = x + self.drop_path(self.mlp(self.norm2(x)))
        return x

class VisionTransformer_Token(nn.Module):
    def __init__(self, img_size=224, patch_size=16, in_chans=3, num_classes=1000, embed_dim=768, depth=12,
                 num_heads=12, mlp_ratio=4., qkv_bias=False, qk_scale=None, drop_rate=0., attn_drop_rate=0.,
                 drop_path_rate=0., norm_layer=nn.LayerNorm, pruning_type='unstructure'):
        super().__init__()
        self.pruning_type = pruning_type
        self.num_classes = num_classes
        self.num_features = self.embed_dim = embed_dim
        self.patch_embed = nn.Conv2d(in_chans, embed_dim, kernel_size=patch_size, stride=patch_size)
        num_patches = (img_size // patch_size) * (img_size // patch_size)
        self.cls_token = nn.Parameter(torch.zeros(1, 1, embed_dim))
        self.pos_embed = nn.Parameter(torch.zeros(1, num_patches + 1, embed_dim))
        self.pos_drop = nn.Dropout(p=drop_rate)
        dpr = [x.item() for x in torch.linspace(0, drop_path_rate, depth)]
        self.blocks = nn.ModuleList([
            Block_Token(embed_dim, num_heads=num_heads, mlp_ratio=mlp_ratio, qkv_bias=qkv_bias, qk_scale=qk_scale,
                        drop=drop_rate, attn_drop=attn_drop_rate, drop_path=dpr[i], norm_layer=norm_layer)
            for i in range(depth)])
        self.norm = norm_layer(embed_dim)
        self.head = nn.Linear(embed_dim, num_classes) if num_classes > 0 else nn.Identity()
        trunc_normal_(self.pos_embed, std=.02)
        trunc_normal_(self.cls_token, std=.02)
        self.apply(self._init_weights)

    def _init_weights(self, m):
        if isinstance(m, nn.Linear):
            trunc_normal_(m.weight, std=.02)
            if isinstance(m, nn.Linear) and m.bias is not None:
                nn.init.constant_(m.bias, 0)
        elif isinstance(m, nn.LayerNorm):
            nn.init.constant_(m.bias, 0)
            nn.init.constant_(m.weight, 1.0)

    def forward_features(self, x, tau=-1, number=197):
        B = x.shape[0]
        x = self.patch_embed(x).flatten(2).transpose(1, 2)
        cls_tokens = self.cls_token.expand(B, -1, -1)
        x = torch.cat((cls_tokens, x), dim=1)
        x = x + self.pos_embed
        x = self.pos_drop(x)
        for blk in self.blocks:
            x = blk(x, tau, number)
        x = self.norm(x)
        return x[:, 0]

    def forward(self, x, tau=-1, number=197):
        x = self.forward_features(x, tau, number)
        x = self.head(x)
        return x


